var CaptchaDSGVO = (function (exports) {
  'use strict';

  const CSS = /* css */ `
:host {
  display: block;
  font-family: var(--captcha-font, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif);
  font-size: var(--captcha-font-size, 14px);
  line-height: 1.5;
  color: var(--captcha-text, #333);
  --_bg: var(--captcha-bg, #f8f9fa);
  --_border: var(--captcha-border, #dee2e6);
  --_accent: var(--captcha-accent, #0066cc);
  --_success: var(--captcha-success, #28a745);
  --_error: var(--captcha-error, #dc3545);
  --_radius: var(--captcha-radius, 8px);
}

:host([theme="dark"]) {
  color: var(--captcha-text, #e0e0e0);
  --_bg: var(--captcha-bg, #1e1e1e);
  --_border: var(--captcha-border, #444);
}

@media (prefers-color-scheme: dark) {
  :host([theme="auto"]) {
    color: var(--captcha-text, #e0e0e0);
    --_bg: var(--captcha-bg, #1e1e1e);
    --_border: var(--captcha-border, #444);
  }
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

.container {
  background: var(--_bg);
  border: 1px solid var(--_border);
  border-radius: var(--_radius);
  padding: 16px;
  max-width: 400px;
}

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

/* Status row */
.status {
  display: flex;
  align-items: center;
  gap: 12px;
}

.status-text {
  flex: 1;
}

/* Spinner */
.spinner {
  width: 22px;
  height: 22px;
  border: 3px solid var(--_border);
  border-top-color: var(--_accent);
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
  flex-shrink: 0;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

@media (prefers-reduced-motion: reduce) {
  .spinner { animation: none; }
}

/* Icons */
.icon {
  flex-shrink: 0;
  width: 24px;
  height: 24px;
}

.icon-success {
  color: var(--_success);
}

.icon-error {
  color: var(--_error);
}

/* Progress bar */
.progress {
  height: 3px;
  background: var(--_border);
  border-radius: 2px;
  margin-top: 10px;
  overflow: hidden;
}

.progress-bar {
  height: 100%;
  background: var(--_accent);
  border-radius: 2px;
  transition: width 0.3s ease;
}

/* Challenge form */
.challenge {
  margin-top: 12px;
}

.challenge-question {
  font-weight: 600;
  margin-bottom: 4px;
}

.challenge-hint {
  font-size: 0.9em;
  opacity: 0.7;
  margin-bottom: 8px;
}

.input-row {
  display: flex;
  gap: 8px;
}

.input {
  flex: 1;
  padding: 8px 12px;
  border: 1px solid var(--_border);
  border-radius: calc(var(--_radius) / 2);
  font: inherit;
  background: var(--_bg);
  color: inherit;
}

.input:focus {
  outline: 2px solid var(--_accent);
  outline-offset: 1px;
}

.btn {
  padding: 8px 16px;
  background: var(--_accent);
  color: #fff;
  border: none;
  border-radius: calc(var(--_radius) / 2);
  font: inherit;
  cursor: pointer;
  white-space: nowrap;
}

.btn:hover { opacity: 0.9; }

.btn:focus-visible {
  outline: 2px solid var(--_accent);
  outline-offset: 2px;
}

.btn:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

/* Retry link */
.retry-link {
  display: inline;
  background: none;
  border: none;
  color: var(--_accent);
  cursor: pointer;
  font: inherit;
  padding: 0;
  text-decoration: underline;
}

.retry-link:focus-visible {
  outline: 2px solid var(--_accent);
  outline-offset: 2px;
}

/* Branding */
.branding {
  margin-top: 8px;
  font-size: 11px;
  opacity: 0.4;
  text-align: right;
}

.branding-link {
  color: inherit;
  text-decoration: underline;
}

.branding-link:hover {
  opacity: 0.8;
}

.branding-link:focus-visible {
  outline: 1px solid var(--_accent);
  outline-offset: 1px;
}
`;

  const de = {
      loading: 'Sicherheitspr\u00fcfung wird geladen\u2026',
      solving: 'Sicherheitspr\u00fcfung l\u00e4uft\u2026',
      success: 'Sicherheitspr\u00fcfung bestanden',
      error: 'Sicherheitspr\u00fcfung fehlgeschlagen',
      challengeLabel: 'Bitte beantworten Sie die folgende Frage:',
      challengePlaceholder: 'Ihre Antwort\u2026',
      challengeSubmit: 'Absenden',
      timeout: 'Zeit\u00fcberschreitung. Bitte erneut versuchen.',
      tooManyRequests: 'Zu viele Anfragen. Bitte warten.',
      networkError: 'Verbindungsfehler. Bitte erneut versuchen.',
      retryIn: (s) => `Erneut in ${s}\u202Fs\u2026`,
      retry: 'Erneut versuchen',
      powHint: 'Ihr Browser f\u00fchrt eine kurze Berechnung durch\u2026',
      branding: 'DSGVO-konformes CAPTCHA',
      privacyLink: 'Datenschutz',
  };
  const en = {
      loading: 'Loading security check\u2026',
      solving: 'Security check in progress\u2026',
      success: 'Security check passed',
      error: 'Security check failed',
      challengeLabel: 'Please answer the following question:',
      challengePlaceholder: 'Your answer\u2026',
      challengeSubmit: 'Submit',
      timeout: 'Timed out. Please try again.',
      tooManyRequests: 'Too many requests. Please wait.',
      networkError: 'Connection error. Please try again.',
      retryIn: (s) => `Retry in ${s}\u202Fs\u2026`,
      retry: 'Try again',
      powHint: 'Your browser is performing a short computation\u2026',
      branding: 'GDPR-compliant CAPTCHA',
      privacyLink: 'Privacy',
  };
  const translations = { de, en };
  function t(lang) {
      return translations[lang] || translations.de;
  }

  function initial() {
      return {
          state: 'idle',
          stage: 0,
          challengeToken: null,
          verificationToken: null,
          expiresIn: 0,
          question: null,
          errorCode: null,
          retryAfter: 0,
          powIterations: 0,
      };
  }
  function transition(ctx, evt) {
      const s = ctx.state;
      if (s === 'idle' && evt.type === 'START') {
          return { ...ctx, state: 'loading' };
      }
      if (s === 'loading' && evt.type === 'CHALLENGE_RECEIVED') {
          return evt.stage === 0
              ? { ...ctx, state: 'solving', stage: 0, powIterations: 0 }
              : { ...ctx, state: 'challenge', stage: evt.stage };
      }
      if (s === 'solving' && evt.type === 'POW_PROGRESS') {
          return { ...ctx, powIterations: evt.iterations };
      }
      if ((s === 'solving' || s === 'challenge') && evt.type === 'VERIFY_SUCCESS') {
          return {
              ...ctx,
              state: 'success',
              verificationToken: evt.token,
              expiresIn: evt.expiresIn,
          };
      }
      if ((s === 'solving' || s === 'challenge') && evt.type === 'ESCALATE') {
          return {
              ...ctx,
              state: 'challenge',
              stage: evt.stage,
              challengeToken: evt.token,
              question: evt.question,
          };
      }
      if (s === 'challenge' && evt.type === 'CHALLENGE_FAILED') {
          return {
              ...ctx,
              state: 'error',
              errorCode: 'challenge_failed',
              retryAfter: evt.retryAfter ?? 30,
          };
      }
      if ((s === 'loading' || s === 'solving' || s === 'challenge') && evt.type === 'ERROR') {
          return {
              ...ctx,
              state: 'error',
              errorCode: evt.code,
              retryAfter: evt.retryAfter ?? 0,
          };
      }
      if (s === 'solving' && evt.type === 'TIMEOUT') {
          return { ...ctx, state: 'error', errorCode: 'timeout' };
      }
      if (s === 'error' && evt.type === 'RETRY') {
          return initial();
      }
      if (s === 'success' && evt.type === 'TIMEOUT') {
          return initial();
      }
      return ctx;
  }

  class ApiError extends Error {
      constructor(message, status, retryAfter) {
          super(message);
          this.status = status;
          this.retryAfter = retryAfter;
          this.name = 'ApiError';
      }
  }
  async function request(url, body) {
      let res;
      try {
          res = await fetch(url, {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify(body),
          });
      }
      catch {
          throw new ApiError('network_error', 0);
      }
      if (res.status === 429) {
          const data = await res.json().catch(() => ({}));
          throw new ApiError('too_many_requests', 429, data.retry_after ?? 30);
      }
      if (res.status === 410) {
          throw new ApiError('token_expired', 410);
      }
      if (!res.ok) {
          throw new ApiError(`http_${res.status}`, res.status);
      }
      return res.json();
  }
  function requestChallenge(serverUrl, formId, lang) {
      return request(`${serverUrl}/api/challenge`, { form_id: formId, lang });
  }
  function submitSolution(serverUrl, token, solution) {
      return request(`${serverUrl}/api/verify`, { token, solution });
  }

  /**
   * Proof-of-Work Web Worker code.
   * Embedded as a string constant so we can create a Blob URL at runtime
   * (avoids a separate network request, CSP-compatible with worker-src blob:).
   *
   * Performance: Uses batched crypto.subtle.digest calls (64 hashes per await)
   * to amortize the async overhead. This is 3-5x faster than sequential awaits.
   */
  const POW_WORKER_CODE = `"use strict";
self.onmessage = async function (e) {
  var prefix = e.data.prefix;
  var difficulty = e.data.difficulty;
  var encoder = new TextEncoder();
  var BATCH = 64;
  var nonce = 0;

  while (true) {
    /* Build a batch of hash inputs */
    var promises = new Array(BATCH);
    var hexes = new Array(BATCH);
    for (var j = 0; j < BATCH; j++) {
      hexes[j] = (nonce + j).toString(16);
      promises[j] = crypto.subtle.digest(
        "SHA-256",
        encoder.encode(prefix + hexes[j])
      );
    }

    var results = await Promise.all(promises);

    /* Check each result in the batch */
    for (var j = 0; j < BATCH; j++) {
      var arr = new Uint8Array(results[j]);
      var bits = 0;
      for (var i = 0; i < arr.length; i++) {
        if (arr[i] === 0) { bits += 8; continue; }
        var b = arr[i];
        while ((b & 0x80) === 0) { bits++; b <<= 1; }
        break;
      }

      if (bits >= difficulty) {
        self.postMessage({ type: "result", nonce: hexes[j] });
        return;
      }
    }

    nonce += BATCH;
    if (nonce % 10048 < BATCH) {
      self.postMessage({ type: "progress", iterations: nonce });
    }
  }
};
`;

  /* ---------- SVG Icons (inline, no external deps) ---------- */
  const ICON_CHECK = `<svg class="icon icon-success" viewBox="0 0 24 24" fill="none" stroke="currentColor" 
stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M20 6 9 
17l-5-5"/></svg>`;
  const ICON_X = `<svg class="icon icon-error" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" 
stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>`;
  /* ---------- Renderers per state ---------- */
  function renderLoading(tr) {
      return `
    <div class="status">
      <div class="spinner" aria-hidden="true"></div>
      <span class="status-text">${tr.loading}</span>
    </div>`;
  }
  function renderSolving(tr, iterations) {
      // Estimate progress assuming ~262144 iterations (difficulty 18)
      const pct = Math.min(95, Math.round((iterations / 262144) * 100));
      return `
    <div class="status">
      <div class="spinner" aria-hidden="true"></div>
      <span class="status-text">${tr.powHint}</span>
    </div>
    <div class="progress" role="progressbar" aria-valuenow="${pct}" aria-valuemin="0" aria-valuemax="100">
      <div class="progress-bar" style="width:${pct}%"></div>
    </div>`;
  }
  function renderChallenge(tr, question) {
      const hintHtml = question.hint ? `<div class="challenge-hint">${esc(question.hint)}</div>` : '';
      return `
    <div class="status">
      <div class="spinner" aria-hidden="true" style="visibility:hidden"></div>
      <span class="status-text">${tr.challengeLabel}</span>
    </div>
    <div class="challenge">
      <div class="challenge-question" id="challenge-question">${esc(question.text)}</div>
      ${hintHtml}
      <div class="input-row">
        <label class="sr-only" for="captcha-answer">${tr.challengeLabel}</label>
        <input id="captcha-answer" class="input" type="text"
               placeholder="${esc(tr.challengePlaceholder)}"
               autocomplete="off" aria-required="true"
               aria-describedby="challenge-question" />
        <button class="btn" type="button" data-action="submit">
          ${tr.challengeSubmit}
        </button>
      </div>
    </div>`;
  }
  function renderSuccess(tr) {
      return `
    <div class="status">
      ${ICON_CHECK}
      <span class="status-text">${tr.success}</span>
    </div>`;
  }
  function renderError(tr, code, retryAfter) {
      let msg;
      switch (code) {
          case 'too_many_requests':
              msg = tr.tooManyRequests;
              break;
          case 'network_error':
              msg = tr.networkError;
              break;
          case 'timeout':
              msg = tr.timeout;
              break;
          default:
              msg = tr.error;
      }
      const retryHtml = retryAfter > 0
          ? `<span data-countdown="${retryAfter}">${tr.retryIn(retryAfter)}</span>`
          : `<button class="retry-link" type="button" data-action="retry">${tr.retry}</button>`;
      return `
    <div class="status">
      ${ICON_X}
      <span class="status-text">${msg}</span>
    </div>
    <div style="margin-top:8px">${retryHtml}</div>`;
  }
  /* ---------- Main render function ---------- */
  function render(ctx, tr, privacyUrl) {
      let body;
      switch (ctx.state) {
          case 'idle':
          case 'loading':
              body = renderLoading(tr);
              break;
          case 'solving':
              body = renderSolving(tr, ctx.powIterations);
              break;
          case 'challenge':
              body = ctx.question ? renderChallenge(tr, ctx.question) : renderLoading(tr);
              break;
          case 'success':
              body = renderSuccess(tr);
              break;
          case 'error':
              body = renderError(tr, ctx.errorCode, ctx.retryAfter);
              break;
          default:
              body = '';
      }
      const brandingHtml = privacyUrl && isSafeUrl(privacyUrl)
          ? `${tr.branding} · <a class="branding-link" href="${esc(privacyUrl)}" target="_blank" rel="noopener 
noreferrer">${tr.privacyLink}</a>`
          : tr.branding;
      return `
    <div class="container" role="group" aria-label="${tr.branding}">
      <div role="status" aria-live="polite" class="sr-only" data-announce></div>
      ${body}
      <div class="branding">${brandingHtml}</div>
    </div>`;
  }
  /** Returns the screen-reader-friendly status text for the current state. */
  function announceText(ctx, tr) {
      switch (ctx.state) {
          case 'loading':
              return tr.loading;
          case 'solving':
              return tr.solving;
          case 'challenge':
              return tr.challengeLabel;
          case 'success':
              return tr.success;
          case 'error':
              return tr.error;
          default:
              return '';
      }
  }
  /* ---------- Helpers ---------- */
  function esc(s) {
      const el = document.createElement('span');
      el.textContent = s;
      return el.innerHTML.replace(/"/g, '&quot;').replace(/'/g, '&#39;');
  }
  /** Only allow https: URLs and relative paths — blocks javascript:, data:, protocol-relative, etc. */
  function isSafeUrl(url) {
      const trimmed = url.trim();
      if (trimmed.startsWith('/') && !trimmed.startsWith('//'))
          return true;
      try {
          const parsed = new URL(trimmed);
          return parsed.protocol === 'https:';
      }
      catch {
          return false;
      }
  }

  /**
   * <captcha-widget> — DSGVO-konformes CAPTCHA Web Component
   *
   * Attributes:
   *   form-id      (optional) — ID of the form to protect (auto-detects via closest('form') if omitted)
   *   server-url   (required) — Base URL of the CAPTCHA server
   *   lang         (optional) — "de" | "en" (default: "de")
   *   theme        (optional) — "light" | "dark" | "auto" (default: "light")
   *   privacy-url  (optional) — URL to privacy policy; if set, a "Datenschutz"/"Privacy" link appears in the branding 
line
   *
   * Events:
   *   captcha-solved — detail: { verificationToken: string }
   *
   * The widget automatically injects a hidden <input name="captcha_token">
   * into the parent form.
   */
  const POW_TIMEOUT_MS = 60000; // 60 s max for PoW computation
  class CaptchaWidget extends HTMLElement {
      static get observedAttributes() {
          return ['form-id', 'server-url', 'lang', 'theme', 'privacy-url'];
      }
      /* ---- Attribute helpers ---- */
      get formId() {
          return this.getAttribute('form-id') ?? '';
      }
      get serverUrl() {
          return (this.getAttribute('server-url') ?? '').replace(/\/+$/, '');
      }
      get widgetLang() {
          const l = this.getAttribute('lang');
          return l === 'en' ? 'en' : 'de';
      }
      get privacyUrl() {
          return this.getAttribute('privacy-url') ?? '';
      }
      constructor() {
          super();
          this.ctx = initial();
          this.worker = null;
          this.powTimer = null;
          this.expiryTimer = null;
          this.countdownTimer = null;
          this.hiddenInput = null;
          this.initialized = false;
          this.root = this.attachShadow({ mode: 'open' });
          // Apply styles — prefer Constructable Stylesheets, fallback to <style>
          try {
              const sheet = new CSSStyleSheet();
              sheet.replaceSync(CSS);
              this.root.adoptedStyleSheets = [sheet];
          }
          catch {
              const style = document.createElement('style');
              style.textContent = CSS;
              this.root.appendChild(style);
          }
      }
      connectedCallback() {
          if (!this.initialized) {
              this.initialized = true;
              this.renderUI();
              this.start();
          }
      }
      disconnectedCallback() {
          this.cleanup();
      }
      attributeChangedCallback() {
          if (this.initialized) {
              this.renderUI();
          }
      }
      /* ================================================================
       *  State management
       * ================================================================ */
      dispatch(evt) {
          const prev = this.ctx.state;
          this.ctx = transition(this.ctx, evt);
          this.renderUI();
          // Post-transition side effects
          if (this.ctx.state !== prev) {
              this.announce();
              if (this.ctx.state === 'challenge') {
                  // Focus the input after render
                  requestAnimationFrame(() => {
                      const input = this.root.querySelector('#captcha-answer');
                      input?.focus();
                  });
              }
          }
      }
      /* ================================================================
       *  Core flow
       * ================================================================ */
      async start() {
          this.dispatch({ type: 'START' });
          try {
              const challenge = await requestChallenge(this.serverUrl, this.formId, this.widgetLang);
              this.ctx.challengeToken = challenge.token;
              this.dispatch({
                  type: 'CHALLENGE_RECEIVED',
                  stage: challenge.stage,
              });
              if (challenge.stage === 0 && challenge.pow) {
                  // Set question data if present (shouldn't be for stage 0)
                  await this.solvePoW(challenge.token, challenge.pow);
              }
              else if (challenge.question) {
                  // Stage 1 or 2 — directly show question
                  this.ctx = {
                      ...this.ctx,
                      challengeToken: challenge.token,
                      question: challenge.question,
                  };
                  this.renderUI();
                  this.bindChallengeEvents();
              }
          }
          catch (err) {
              this.handleError(err);
          }
      }
      async solvePoW(token, pow) {
          const blob = new Blob([POW_WORKER_CODE], { type: 'application/javascript' });
          const url = URL.createObjectURL(blob);
          try {
              this.worker = new Worker(url);
          }
          finally {
              URL.revokeObjectURL(url);
          }
          // Timeout for PoW
          this.powTimer = setTimeout(() => {
              this.worker?.terminate();
              this.worker = null;
              this.dispatch({ type: 'TIMEOUT' });
          }, POW_TIMEOUT_MS);
          this.worker.onmessage = async (e) => {
              const data = e.data;
              if (data.type === 'progress') {
                  this.dispatch({ type: 'POW_PROGRESS', iterations: data.iterations });
                  return;
              }
              if (data.type === 'result') {
                  this.clearPowTimer();
                  this.worker?.terminate();
                  this.worker = null;
                  try {
                      const res = await submitSolution(this.serverUrl, token, {
                          nonce: data.nonce,
                      });
                      this.handleVerifyResponse(res);
                  }
                  catch (err) {
                      this.handleError(err);
                  }
              }
          };
          this.worker.onerror = () => {
              this.clearPowTimer();
              this.worker = null;
              this.dispatch({ type: 'ERROR', code: 'worker_error' });
          };
          this.worker.postMessage({
              prefix: pow.prefix,
              difficulty: pow.difficulty,
          });
      }
      handleVerifyResponse(res) {
          if (res.valid && res.verification_token) {
              this.dispatch({
                  type: 'VERIFY_SUCCESS',
                  token: res.verification_token,
                  expiresIn: res.expires_in ?? 120,
              });
              this.onSolved(res.verification_token, res.expires_in ?? 120);
              return;
          }
          if (res.escalate && res.next) {
              const next = res.next;
              if (next.question) {
                  this.dispatch({
                      type: 'ESCALATE',
                      stage: next.stage,
                      token: next.token,
                      question: next.question,
                  });
                  this.bindChallengeEvents();
              }
              return;
          }
          // Final rejection
          this.dispatch({
              type: 'CHALLENGE_FAILED',
              retryAfter: res.retry_after,
          });
          this.startCountdown(res.retry_after ?? 30);
      }
      /* ================================================================
       *  Challenge interaction
       * ================================================================ */
      bindChallengeEvents() {
          requestAnimationFrame(() => {
              const btn = this.root.querySelector('[data-action="submit"]');
              const input = this.root.querySelector('#captcha-answer');
              btn?.addEventListener('click', () => this.submitChallengeAnswer());
              input?.addEventListener('keydown', (e) => {
                  if (e.key === 'Enter') {
                      e.preventDefault();
                      this.submitChallengeAnswer();
                  }
              });
          });
      }
      async submitChallengeAnswer() {
          const input = this.root.querySelector('#captcha-answer');
          const btn = this.root.querySelector('[data-action="submit"]');
          const answer = input?.value.trim();
          if (!answer || !this.ctx.challengeToken)
              return;
          // Disable UI while verifying
          if (input)
              input.disabled = true;
          if (btn)
              btn.disabled = true;
          try {
              const res = await submitSolution(this.serverUrl, this.ctx.challengeToken, {
                  answer,
              });
              this.handleVerifyResponse(res);
          }
          catch (err) {
              this.handleError(err);
          }
      }
      /* ================================================================
       *  Success handling
       * ================================================================ */
      onSolved(token, expiresIn) {
          // Inject hidden input into form
          const form = this.formId
              ? document.getElementById(this.formId)
              : this.closest('form');
          if (form) {
              if (!this.hiddenInput) {
                  this.hiddenInput = document.createElement('input');
                  this.hiddenInput.type = 'hidden';
                  this.hiddenInput.name = 'captcha_token';
                  form.appendChild(this.hiddenInput);
              }
              this.hiddenInput.value = token;
          }
          // Dispatch custom event for SPA integration
          this.dispatchEvent(new CustomEvent('captcha-solved', {
              bubbles: true,
              composed: true,
              detail: { verificationToken: token },
          }));
          // Auto-refresh before expiry
          this.expiryTimer = setTimeout(() => {
              this.dispatch({ type: 'TIMEOUT' });
              this.start();
          }, (expiresIn - 5) * 1000); // Refresh 5s before expiry
      }
      /* ================================================================
       *  Error handling
       * ================================================================ */
      handleError(err) {
          if (err instanceof ApiError) {
              this.dispatch({
                  type: 'ERROR',
                  code: err.message,
                  retryAfter: err.retryAfter,
              });
              if (err.retryAfter) {
                  this.startCountdown(err.retryAfter);
              }
              else {
                  this.bindRetryEvent();
              }
          }
          else {
              this.dispatch({ type: 'ERROR', code: 'network_error' });
              this.bindRetryEvent();
          }
      }
      bindRetryEvent() {
          requestAnimationFrame(() => {
              const btn = this.root.querySelector('[data-action="retry"]');
              btn?.addEventListener('click', () => this.retry());
          });
      }
      retry() {
          this.cleanup();
          this.dispatch({ type: 'RETRY' });
          this.start();
      }
      /* ================================================================
       *  Countdown (retry-after)
       * ================================================================ */
      startCountdown(seconds) {
          let remaining = seconds;
          const tr = t(this.widgetLang);
          this.countdownTimer = setInterval(() => {
              remaining--;
              const el = this.root.querySelector('[data-countdown]');
              if (el) {
                  if (remaining <= 0) {
                      this.clearCountdown();
                      el.innerHTML = `<button class="retry-link" type="button" 
data-action="retry">${tr.retry}</button>`;
                      this.bindRetryEvent();
                  }
                  else {
                      el.textContent = tr.retryIn(remaining);
                  }
              }
          }, 1000);
      }
      /* ================================================================
       *  Rendering
       * ================================================================ */
      renderUI() {
          const tr = t(this.widgetLang);
          // Find or create the content container (preserve the style element)
          let container = this.root.querySelector('.captcha-root');
          if (!container) {
              container = document.createElement('div');
              container.className = 'captcha-root';
              this.root.appendChild(container);
          }
          container.innerHTML = render(this.ctx, tr, this.privacyUrl || undefined);
      }
      announce() {
          const el = this.root.querySelector('[data-announce]');
          if (el) {
              el.textContent = announceText(this.ctx, t(this.widgetLang));
          }
      }
      /* ================================================================
       *  Cleanup
       * ================================================================ */
      clearPowTimer() {
          if (this.powTimer) {
              clearTimeout(this.powTimer);
              this.powTimer = null;
          }
      }
      clearCountdown() {
          if (this.countdownTimer) {
              clearInterval(this.countdownTimer);
              this.countdownTimer = null;
          }
      }
      cleanup() {
          this.worker?.terminate();
          this.worker = null;
          this.clearPowTimer();
          this.clearCountdown();
          if (this.expiryTimer) {
              clearTimeout(this.expiryTimer);
              this.expiryTimer = null;
          }
      }
  }
  /* Register the custom element */
  if (!customElements.get('captcha-widget')) {
      customElements.define('captcha-widget', CaptchaWidget);
  }

  exports.CaptchaWidget = CaptchaWidget;

  return exports;

})({});

